230→async function forwardToN8n(webhookPath: string, payload: unknown) {
231→  const N8N_BASE_URL = Deno.env.get('N8N_BASE_URL');
232→  if (!N8N_BASE_URL) {
233→    console.error('N8N_BASE_URL not configured, skipping forward');
234→    return { skipped: true };
235→  }
236→
237→  const body = JSON.stringify(payload);
238→
239→  // Sign the payload
240→  const encoder = new TextEncoder();
241→  const key = await crypto.subtle.importKey(
242→    'raw',
243→    encoder.encode(N8N_WEBHOOK_SECRET),
244→    { name: 'HMAC', hash: 'SHA-256' },
245→    false,
246→    ['sign']
247→  );
248→  const sig = await crypto.subtle.sign('HMAC', key, encoder.encode(body));
249→  const signature = Array.from(new Uint8Array(sig))
250→    .map((b) => b.toString(16).padStart(2, '0'))
251→    .join('');
252→
253→  const url = `${N8N_BASE_URL}${webhookPath}`;
254→  const res = await fetch(url, {
255→    method: 'POST',
256→    headers: {
257→      'Content-Type': 'application/json',
258→      'x-webhook-signature': signature,
259→    },
260→    body,
261→  });
262→
263→  if (!res.ok) {
264→    const text = await res.text();
265→    console.error(`n8n forward failed: ${res.status} — ${text}`);
266→    return { error: true, status: res.status };
267→  }
268→
269→  return { forwarded: true };
270→}
