285→    // MODE 1 — Supabase → n8n (forward event)
286→    if (payload.event) {
287→      const event = payload.event as string;
288→      const eventPayload = payload.payload || {};
289→
290→      switch (event) {
291→        case 'new_scan':
292→          // Forward to welcome workflow if first scan
293→          if (eventPayload.is_first_scan) {
294→            await forwardToN8n('/webhook/welcome-new-customer', eventPayload);
295→          }
296→          // Always forward to smart-engagement
297→          await forwardToN8n('/webhook/smart-engagement', eventPayload);
298→          break;
299→
300→        case 'campaign_scheduled':
301→          // Handled by cron workflow, but log the event
302→          await supabaseAdmin.from('workflow_logs').insert({
303→            workflow_name: 'event-campaign-scheduled',
304→            status: 'success',
305→            merchant_id: eventPayload.merchant_id || null,
306→            output_data: eventPayload,
307→          });
308→          break;
309→
310→        default:
311→          return errorResponse('UNKNOWN_EVENT', `Unknown event: ${event}`, 400);
312→      }
313→
314→      return successResponse({ forwarded: true, event });
315→    }
316→
317→    // MODE 2 — n8n → Supabase (callback with HMAC)
318→    if (payload.action) {
319→      // Validate HMAC signature
320→      const signature = req.headers.get('x-n8n-signature') || '';
321→      if (N8N_WEBHOOK_SECRET && signature) {
322→        const valid = await validateSignature(rawBody, signature, N8N_WEBHOOK_SECRET);
323→        if (!valid) {
324→          return errorResponse('INVALID_SIGNATURE', 'HMAC signature invalid', 403);
325→        }
326→      }
327→
328→      const action = payload.action as string;
329→      const data = payload.data || {};
330→
331→      let result: unknown;
332→
333→      switch (action) {
334→        case 'log_workflow':
335→          result = await handleLogWorkflow(data);
336→          break;
337→        case 'create_campaign':
338→          result = await handleCreateCampaign(data);
339→          break;
340→        case 'launch_campaign':
341→          result = await handleLaunchCampaign(data);
342→          break;
343→        case 'save_suggestions':
344→          result = await handleSaveSuggestions(data);
345→          break;
346→        case 'save_report':
347→          result = await handleSaveReport(data);
348→          break;
349→        case 'send_push':
350→          result = await handleSendPush(data);
351→          break;
352→        case 'complete_campaign':
353→          result = await handleCompleteCampaign(data);
354→          break;
355→        default:
356→          return errorResponse('UNKNOWN_ACTION', `Unknown action: ${action}`, 400);
357→      }
358→
359→      return successResponse(result);
360→    }
361→
362→    return errorResponse('INVALID_REQUEST', 'Missing event or action field', 400);
363→  } catch (err) {
364→    console.error('n8n-webhook-handler error:', err);
365→    return errorResponse(
366→      'INTERNAL_ERROR',
367→      err instanceof Error ? err.message : 'Unexpected error',
