 12→  if (req.method === 'OPTIONS') {
 13→    return corsResponse();
 14→  }
 15→
 16→  try {
 17→    // 1. Authentification
 18→    const user = await getAuthUser(req);
 19→    if (!user) {
 20→      return errorResponse('NOT_AUTHENTICATED', 'Le client doit etre connecte', 401);
 21→    }
 22→
 23→    // 2. Parser le body
 24→    const { token } = await req.json();
 25→    if (!token) {
 26→      return errorResponse('INVALID_TOKEN', 'Token QR manquant');
 27→    }
 28→
 29→    // 3. Valider le token QR
 30→    const { data: qrCode, error: qrError } = await supabaseAdmin
 31→      .from('qr_codes')
 32→      .select('*')
 33→      .eq('token', token)
 34→      .eq('is_active', true)
 35→      .single();
 36→
 37→    if (qrError || !qrCode) {
 38→      return errorResponse('INVALID_TOKEN', 'Token QR non trouve ou inactif');
 39→    }
 40→
 41→    if (qrCode.qr_type !== 'counter') {
 42→      return errorResponse('NOT_COUNTER_QR', 'Ce QR n\'est pas un QR comptoir');
 43→    }
 44→
 45→    const merchantId = qrCode.merchant_id;
 46→
 47→    // 4. Recuperer la config marchand
 48→    const { data: merchant, error: merchantError } = await supabaseAdmin
 49→      .from('merchants')
 50→      .select('id, business_name, points_per_scan, stamps_per_scan, stamps_per_card, loyalty_type')
 51→      .eq('id', merchantId)
 52→      .single();
 53→
 54→    if (merchantError || !merchant) {
 55→      return errorResponse('MERCHANT_NOT_FOUND', 'Marchand introuvable');
 56→    }
 57→
 58→    // 5. Recuperer le customer_id depuis le profil
 59→    const { data: customer, error: customerError } = await supabaseAdmin
 60→      .from('customers')
 61→      .select('id')
 62→      .eq('profile_id', user.id)
 63→      .single();
 64→
 65→    if (customerError || !customer) {
 66→      return errorResponse('NOT_AUTHENTICATED', 'Profil client introuvable');
 67→    }
 68→
 69→    const customerId = customer.id;
 70→
 71→    // 6. Anti-abus : verifier dernier scan < 5 min
 72→    const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000).toISOString();
 73→    const { data: recentScan } = await supabaseAdmin
 74→      .from('scans')
 75→      .select('id')
 76→      .eq('customer_id', customerId)
 77→      .eq('merchant_id', merchantId)
 78→      .gte('scanned_at', fiveMinAgo)
 79→      .limit(1)
 80→      .maybeSingle();
 81→
 82→    if (recentScan) {
 83→      return errorResponse('SCAN_TOO_RECENT', 'Scan trop recent, veuillez attendre 5 minutes');
 84→    }
 85→
 86→    // 7. Recuperer ou creer la loyalty_card (upsert)
 87→    const { data: existingCard } = await supabaseAdmin
 88→      .from('loyalty_cards')
 89→      .select('*')
 90→      .eq('customer_id', customerId)
 91→      .eq('merchant_id', merchantId)
 92→      .maybeSingle();
 93→
 94→    let card = existingCard;
 95→
 96→    if (!card) {
 97→      const { data: newCard, error: insertError } = await supabaseAdmin
 98→        .from('loyalty_cards')
 99→        .insert({
100→          customer_id: customerId,
101→          merchant_id: merchantId,
102→          total_points: 0,
103→          total_stamps: 0,
104→          stamps_current_card: 0,
105→          cards_completed: 0,
106→        })
107→        .select()
108→        .single();
109→
110→      if (insertError || !newCard) {
111→        return errorResponse('INTERNAL_ERROR', 'Impossible de creer la carte de fidelite', 500);
112→      }
113→      card = newCard;
114→    }
115→
116→    // 8. Calculer les increments
117→    const loyaltyType = merchant.loyalty_type as string;
118→    let pointsEarned = 0;
119→    let stampsEarned = 0;
120→    let cardCompleted = false;
121→
122→    const updates: Record<string, number> = {};
123→
124→    if (loyaltyType === 'points' || loyaltyType === 'both') {
125→      pointsEarned = merchant.points_per_scan;
126→      updates.total_points = card.total_points + pointsEarned;
127→    }
128→
129→    if (loyaltyType === 'stamps' || loyaltyType === 'both') {
130→      stampsEarned = merchant.stamps_per_scan;
131→      updates.total_stamps = card.total_stamps + stampsEarned;
132→
133→      let newStampsCurrent = card.stamps_current_card + stampsEarned;
134→      let newCardsCompleted = card.cards_completed;
135→
136→      if (newStampsCurrent >= merchant.stamps_per_card) {
137→        newCardsCompleted += 1;
138→        newStampsCurrent = 0;
139→        cardCompleted = true;
140→      }
141→
142→      updates.stamps_current_card = newStampsCurrent;
143→      updates.cards_completed = newCardsCompleted;
144→    }
145→
146→    // 9. Mettre a jour la carte
147→    const { error: updateError } = await supabaseAdmin
148→      .from('loyalty_cards')
149→      .update(updates)
150→      .eq('id', card.id);
151→
152→    if (updateError) {
153→      return errorResponse('INTERNAL_ERROR', 'Erreur mise a jour carte', 500);
154→    }
155→
156→    // 10. Inserer le scan
157→    await supabaseAdmin.from('scans').insert({
158→      customer_id: customerId,
159→      merchant_id: merchantId,
160→      loyalty_card_id: card.id,
161→      points_earned: pointsEarned,
162→      stamps_earned: stampsEarned,
163→    });
164→
165→    // 11. Incrementer uses_count du QR
166→    await supabaseAdmin
167→      .from('qr_codes')
168→      .update({ uses_count: qrCode.uses_count + 1 })
169→      .eq('id', qrCode.id);
170→
171→    // 12. Trigger n8n workflows (fire-and-forget)
172→    const isFirstScan = !existingCard;
173→    const newTotalPoints = updates.total_points ?? card.total_points;
174→    const newTotalStamps = updates.total_stamps ?? card.total_stamps;
175→    const newStampsCurrent = updates.stamps_current_card ?? card.stamps_current_card;
176→
177→    // Count total scans for this customer at this merchant
178→    const { count: scanCount } = await supabaseAdmin
179→      .from('scans')
180→      .select('id', { count: 'exact', head: true })
181→      .eq('customer_id', customerId)
182→      .eq('merchant_id', merchantId);
183→
184→    // Welcome workflow for first scan
185→    if (isFirstScan) {
186→      triggerN8nWorkflow('/webhook/welcome-new-customer', {
187→        customer_id: customerId,
188→        merchant_id: merchantId,
189→        profile_id: user.id,
190→      }).catch((err) => console.error('n8n welcome trigger failed:', err));
191→    }
192→
193→    // Smart engagement workflow for every scan
194→    triggerN8nWorkflow('/webhook/smart-engagement', {
195→      customer_id: customerId,
196→      merchant_id: merchantId,
197→      profile_id: user.id,
198→      total_scans: scanCount || 1,
199→      total_points: newTotalPoints,
200→      total_stamps: newTotalStamps,
201→      stamps_current_card: newStampsCurrent,
202→      card_completed: cardCompleted,
203→    }).catch((err) => console.error('n8n smart-engagement trigger failed:', err));
204→
205→    // 13. Reponse
206→    return successResponse({
207→      merchant_id: merchantId,
208→      merchant_name: merchant.business_name,
209→      points_earned: pointsEarned,
210→      stamps_earned: stampsEarned,
211→      total_points: newTotalPoints,
212→      total_stamps: newTotalStamps,
213→      stamps_current_card: newStampsCurrent,
214→      stamps_per_card: merchant.stamps_per_card,
215→      card_completed: cardCompleted,
216→      is_first_scan: isFirstScan,
217→    });
218→  } catch (err) {
219→    return errorResponse('INTERNAL_ERROR', 'Erreur serveur inattendue', 500);
220→  }
221→});
